mapper.select:
SELECT es.id, es.clinic_id AS clinicId, c.clinic_name AS clinicName, es.patient_id AS patientId, p.patient_name AS patientName, es.medical_record_id AS medicalRecordId, mr.record_no AS medicalRecordNo, es.signer_name AS signerName, es.signer_type AS signerType, es.relation_to_patient AS relationToPatient, es.signature_file_id AS signatureFileId, fa.file_name AS signatureFileName, fa.file_url AS signatureFileUrl, es.signed_at AS signedAt, es.ip_address AS ipAddress, es.device_info AS deviceInfo, es.remark, es.created_at AS createdAt FROM electronic_signature es LEFT JOIN clinic c ON c.id = es.clinic_id LEFT JOIN patient p ON p.id = es.patient_id LEFT JOIN medical_record mr ON mr.id = es.medical_record_id LEFT JOIN file_attachment fa ON fa.id = es.signature_file_id WHERE es.org_id = #{orgId}
AND es.clinic_id = #{query.clinicId}
AND es.patient_id = #{query.patientId}
AND es.medical_record_id = #{query.medicalRecordId}
AND es.signer_type = #{query.signerType}
ORDER BY es.signed_at DESC, es.id DESC
